import{_ as t,o as r,c as a,a5 as o}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"学习记录 #0001：UPS电源系统全景认知","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0001：UPS电源系统全景认知","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第1课 — UPS电源系统全景认知 **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0001-ups-system-overview.md","filePath":"content/power/archive/old-learning-records/0001-ups-system-overview.md","lastUpdated":null}'),s={name:"content/power/archive/old-learning-records/0001-ups-system-overview.md"};function i(n,e,l,c,d,p){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="学习记录-0001-ups电源系统全景认知" tabindex="-1">学习记录 #0001：UPS电源系统全景认知 <a class="header-anchor" href="#学习记录-0001-ups电源系统全景认知" aria-label="Permalink to &quot;学习记录 #0001：UPS电源系统全景认知&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第1课 — UPS电源系统全景认知 <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>UPS的本质是电力电子系统</strong>：不是简单的&quot;电池+逆变器&quot;，而是AC→DC→AC双变换架构，包含PFC、逆变器、双向DC-DC、旁路等多个功率级</li><li><strong>在线式UPS零切换原理</strong>：逆变器始终由直流母线供电，市电断电只是母线能量来源切换，逆变器输出无中断</li><li><strong>软硬结合是核心壁垒</strong>：UPS软件开发者必须理解硬件拓扑，控制算法直接服务于功率电路</li><li><strong>高级拓扑组合</strong>：大功率UPS采用维也纳整流器（三电平PFC）+ LLC（隔离DC-DC）+ 三电平逆变器</li><li><strong>MCU选型关键</strong>：C2000系列是UPS领域主力，TMU硬件加速对SVPWM至关重要</li></ol><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 维也纳整流器的中点平衡具体如何实现？</li><li>[ ] 三电平SVPWM的扇区判断与两电平有何不同？</li><li>[ ] LLC的谐振频率如何设计？增益曲线如何推导？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第2课：电力电子基础——开关器件与基本拓扑</p>',8)])])}const g=t(s,[["render",i]]);export{h as __pageData,g as default};
